The user is asking for a 3D model of a house. However, as a text-based AI, I cannot directly generate or render 3D files (like .obj, .fbx, or .blend). I can, however, provide the code to generate a 3D house using a library like Three.js, which is a popular JavaScript library for 3D graphics in the browser.

Here is a complete, single-file HTML solution using Three.js. You can save this code as an `.html` file (e.g., `house.html`) and open it in any modern web browser to see the 3D model.

### 3D House Generator (Three.js)

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: Arial, sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">3D House Model (Click & Drag to Rotate)</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        // 2. Camera Setup
        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 15, 20);

        // 3. Renderer Setup
        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // 4. Controls (Orbit)
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 5. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 6. Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xeeeeee });
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 });
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.6 });
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x5c3a21 });
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x4caf50 });

        // 7. Building the House
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeometry = new THREE.BoxGeometry(10, 1, 10);
        const floor = new THREE.Mesh(floorGeometry, grassMaterial);
        floor.position.y = -0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Main Body
        const bodyGeometry = new THREE.BoxGeometry(8, 6, 8);
        const body = new THREE.Mesh(bodyGeometry, wallMaterial);
        body.position.y = 3;
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // Roof
        const roofGeometry = new THREE.ConeGeometry(7, 4, 4);
        const roof = new THREE.Mesh(roofGeometry, roofMaterial);
        roof.position.y = 8;
        roof.rotation.y = Math.PI / 4; // Rotate to align with box
        roof.castShadow = true;
        houseGroup.add(roof);

        // Windows
        const windowGeo = new THREE.BoxGeometry(2, 2, 0.2);

        // Front Windows
        const win1 = new THREE.Mesh(windowGeo, windowMaterial);
        win1.position.set(-2, 5, 4.1);
        houseGroup.add(win1);

        const win2 = new THREE.Mesh(windowGeo, windowMaterial);
        win2.position.set(2, 5, 4.1);
        houseGroup.add(win2);

        // Back Windows
        const win3 = new THREE.Mesh(windowGeo, windowMaterial);
        win3.position.set(-2, 5, -4.1);
        houseGroup.add(win3);

        const win4 = new THREE.Mesh(windowGeo, windowMaterial);
        win4.position.set(2, 5, -4.1);
        houseGroup.add(win4);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 4, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 2, 4.1);
        houseGroup.add(door);

        // Chimney
        const chimneyGeo = new THREE.BoxGeometry(1, 3, 1);
        const chimney = new THREE.Mesh(chimneyGeo, wallMaterial);
        chimney.position.set(3, 10, 0);
        chimney.castShadow = true;
        houseGroup.add(chimney);

        scene.add(houseGroup);

        // 8. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  Copy the code block above.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in your web browser.

### Features included:
*   **3D Geometry:** A main body, a cone-shaped roof, a chimney, windows, and a door.
*   **Lighting:** Ambient light for general visibility and a directional light to cast realistic shadows.
*   **Interactivity:** You can click and drag to rotate around the house, and scroll to zoom in/out.
*   **Environment:** A grassy floor and a sky-blue background with fog.
